from flask import Flask, request, jsonify, g
from functools import wraps
import sqlite3
from datetime import datetime
import secrets

app = Flask(__name__)
app.config['DATABASE'] = 'oauth_tokens.db'

def get_db():
    db = sqlite3.connect(app.config['DATABASE'])
    db.row_factory = sqlite3.Row
    return db

def init_db():
    with app.app_context():
        db = get_db()
        db.execute('''
            CREATE TABLE IF NOT EXISTS access_tokens (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                token TEXT UNIQUE NOT NULL,
                client_id TEXT NOT NULL,
                user_id TEXT,
                scope TEXT,
                expires_at TIMESTAMP NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        db.commit()
        db.close()

def validate_token(token):
    db = get_db()
    cursor = db.execute(
        'SELECT * FROM access_tokens WHERE token = ?',
        (token,)
    )
    token_data = cursor.fetchone()
    db.close()
    
    if not token_data:
        return None
    
    expires_at = datetime.fromisoformat(token_data['expires_at'])
    if expires_at < datetime.now():
        return None
    
    return {
        'client_id': token_data['client_id'],
        'user_id': token_data['user_id'],
        'scope': token_data['scope'],
        'expires_at': token_data['expires_at']
    }

def require_oauth(scope=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            
            if not auth_header:
                return jsonify({
                    'error': 'missing_token',
                    'error_description': 'Authorization header is missing'
                }), 401
            
            parts = auth_header.split()
            
            if len(parts) != 2 or parts[0].lower() != 'bearer':
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'Invalid authorization header format. Expected: Bearer <token>'
                }), 401
            
            token = parts[1]
            
            token_data = validate_token(token)
            
            if not token_data:
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'The access token is invalid or has expired'
                }), 401
            
            if scope:
                token_scopes = token_data.get('scope', '').split()
                required_scopes = scope.split() if isinstance(scope, str) else scope
                
                if not any(s in token_scopes for s in required_scopes):
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'The request requires scope: {scope}'
                    }), 403
            
            g.token_data = token_data
            
            return f(*args, **kwargs)
        
        return decorated_function
    return decorator

@app.route('/api/public', methods=['GET'])
def public_endpoint():
    return jsonify({
        'message': 'This is a public endpoint, no authentication required'
    })

@app.route('/api/protected', methods=['GET'])
@require_oauth()
def protected_endpoint():
    return jsonify({
        'message': 'This is a protected endpoint',
        'client_id': g.token_data['client_id'],
        'user_id': g.token_data['user_id']
    })

