@app.route('/oauth/token', methods=['POST'])
def create_token():
    data = request.get_json() or {}
    
    client_id = data.get('client_id')
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    if not client_id:
        return jsonify({'error': 'client_id is required'}), 400
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.now().timestamp() + expires_in
    expires_at_str = datetime.fromtimestamp(expires_at).isoformat()
    
    db = get_db()
    try:
        db.execute(
            'INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at) VALUES (?, ?, ?, ?, ?)',
            (token, client_id, user_id, scope, expires_at_str)
        )
        db.commit()
    except sqlite3.IntegrityError:
        db.close()
        return jsonify({'error': 'Token generation failed'}), 500
    db.close()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    })

@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    data = request.get_json() or {}
    token = data.get('token')
    
    if not token:
        return jsonify({'error': 'token is required'}), 400
    
    db = get_db()
    db.execute('DELETE FROM access_tokens WHERE token = ?', (token,))
    db.commit()
    db.close()
    
    return jsonify({'message': 'Token revoked successfully'})

@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    data = request.get_json() or {}
    token = data.get('token')
    
    if not token:
        return jsonify({'active': False}), 200
    
    token_data = validate_token(token)
    
    if not token_data:
        return jsonify({'active': False}), 200
    
    return jsonify({
        'active': True,
        'client_id': token_data['client_id'],
        'user_id': token_data['user_id'],
        'scope': token_data['scope'],
        'exp': int(datetime.fromisoformat(token_data['expires_at']).timestamp())
    })

